// Extract search query from message
const message = $json.message || '';

let query = message
  .replace(/loker/gi, '')
  .replace(/lowongan/gi, '')
  .replace(/kerja/gi, '')
  .replace(/cari/gi, '')
  .trim();

if (!query || query.length < 2) {
  query = '';
}

return {
  json: {
    ...$json,
    query: query
  }
};

// Format Loker results
const data = $json.data || [];
const query = $('Extract Loker Query').item.json.query;

const results = data.slice(0, 5);

if (results.length === 0) {
  return {
    json: {
      phone: $('Extract Loker Query').item.json.phone,
      chatId: $('Extract Loker Query').item.json.chatId,
      reply: `❌ *TIDAK DITEMUKAN*\n\nTidak ada lowongan kerja dengan kata kunci "${query}"\n\n💡 Coba kata kunci lain seperti:\n• Sopir\n• Admin\n• Karyawan\n• Operator`
    }
  };
}

let replyText = `💼 *HASIL PENCARIAN LOWONGAN KERJA*\n`;
if (query) replyText += `Kata kunci: "${query}"\n`;
replyText += `Ditemukan: ${data.length} lowongan\n`;
replyText += `───────────────────\n\n`;

results.forEach((item, index) => {
  const phone = item.whatsapp || item.phone || '';
  const maskedPhone = phone.length > 8 
    ? phone.substring(0, 4) + '****' + phone.substring(phone.length - 4)
    : phone;

  replyText += `${index + 1}. *${item.judul || item.title || item.posisi}*\n`;
  replyText += `   🏢 ${item.perusahaan || item.company || '-'}\n`;
  replyText += `   📍 ${item.lokasi || item.desa || '-'}\n`;
  if (item.gaji || item.salary) {
    replyText += `   💰 ${item.gaji || item.salary}\n`;
  }
  if (item.tipe || item.type) {
    replyText += `   ⏰ ${item.tipe || item.type}\n`;
  }
  replyText += `   📱 ${maskedPhone}\n\n`;
});

if (data.length > 5) {
  replyText += `_...dan ${data.length - 5} lainnya_\n`;
}

replyText += `\n💡 Ketik LOKER <posisi> untuk pencarian spesifik`;

return {
  json: {
    phone: $('Extract Loker Query').item.json.phone,
    chatId: $('Extract Loker Query').item.json.chatId,
    reply: replyText
  }
};

const replyText = `❌ *ERROR*\n\nGagal mencari data lowongan kerja. Silakan coba lagi nanti.\n\n💡 Ketik MENU untuk melihat daftar layanan.`;

return {
  json: {
    phone: $('Extract Loker Query').item.json.phone,
    chatId: $('Extract Loker Query').item.json.chatId,
    reply: replyText
  }
};
